### useReducer

`useReducer` is an alternative to `useState` for complex state logic. It manages state through a reducer function and dispatched actions, similar to Redux.

---

### Syntax

```jsx
import { useReducer } from 'react';

const [state, dispatch] = useReducer(reducer, initialState);
```

### Basic Example

```jsx
function reducer(state, action) {
  switch (action.type) {
    case 'increment':
      return { count: state.count + 1 };
    case 'decrement':
      return { count: state.count - 1 };
    default:
      return state;
  }
}

function Counter() {
  const [state, dispatch] = useReducer(reducer, { count: 0 });

  return (
    <>
      Count: {state.count}
      <button onClick={() => dispatch({ type: 'increment' })}>+</button>
      <button onClick={() => dispatch({ type: 'decrement' })}>-</button>
    </>
  );
}
```

### Action Conventions

| Pattern | Example |
|---------|---------|
| Type only | `{ type: 'increment' }` |
| With payload | `{ type: 'setUser', payload: user }` |
| Multiple fields | `{ type: 'update', field: 'name', value: 'Alice' }` |

### When to Use

- State depends on previous state
- State logic is complex (multiple sub-values)
- Multiple actions update state in different ways
- State updates are easier to reason about as a reducer

### Lazy Initialization

```jsx
const [state, dispatch] = useReducer(reducer, initialArg, init);
```

> **Key Point:** useReducer is preferred over useState when state logic is complex and involves multiple sub-values or when the next state depends on the previous state heavily. It makes state transitions predictable and testable.

codeExample:
function todoReducer(state, action) {
  switch (action.type) {
    case 'add':
      return [...state, { id: Date.now(), text: action.payload }];
    case 'remove':
      return state.filter(t => t.id !== action.payload);
    case 'toggle':
      return state.map(t =>
        t.id === action.payload ? { ...t, done: !t.done } : t
      );
    default:
      return state;
  }
}

function TodoList() {
  const [todos, dispatch] = useReducer(todoReducer, []);
  return (
    <button onClick={() => dispatch({ type: 'add', payload: 'New task' })}>
      Add
    </button>
  );
}
